INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('indulgences', 'ceb', 'salvation', 'Ang Indulhensya', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa ang indulhensya?', '"Ang Sta,. Iglesya nagtudlo nga ang indulhensya mao ang pagkuha sa kastigo temporal gumikan sa sala nga napasaylo na. Niini, angay nga bantayan nga ang indulhensya way kalabutan sa pagpasaylo sa sala kay kini adto man himoon sa kompisalan kondili mahitungod kini sa pagtangtang sa kastigo temporal nga possible pa nga mahibilin agad sa kahugot sa paghiunulsol nga gihimo sa makasasala. Bisan kon ang sala napasaylo na apan gipangayo sa hustisiya sa Dios nga kinahanglan nga bayran sa hingpit ang kadaut nga miresulta gumikan sa sala. Kining kastigo temporal dili kini nato hunahunaon nga pagpanimalos nga gipahamtang sa Dios tungod sa atong paglapas sa iyang mga sugo kondili mao kini ang resulta nga nagsukad sa kinaiya sa sala. Ang kastigo temporal mahimong atong antosan dinhi sa kalibotan ug kon dili nato hingpit nga kabayran niining kinabuhia adto nato kini antosan sa purgaturyo. Ang Indulhensya mapuslanon alang sa mga buhi ug sa mga kalag sa purgaturyo nga nag-antos pa sa kastigo temporal tungod sa ilang mga sala nga nahimo sa dinhi pa sila sa kalibotan. Alang sa mga buhi ang Sta. Iglesya makahatag og indulhensya pinaagi og “absolution” apan alang sa mga kalag sa purgaturyo sa Sta. Iglesya makapadangat niini ngadto kanila pinaagi og “supplication” kun pagpangaliyupo."'::jsonb, '[{"objection":"Wala na kinahanglana ang pagdawat og indulhensya kondili ang paghinulsol nga nagsukad sa atong gugma sa Dios, “ang gugma mopasaylo sa tanang kalapasan” (Prob. 10:12), “Labaw sa tanan, paghigugmaay kamo sa kinasingkasing gayod, kay ang gugma nagtabon sa daghang mga sala” (1 Ped. 4:8). Wala na kinahanglan ang pagpamayad sa atong bahin kay gihimo na ni Cristo ang hingpit nga pamayad, “Kay naluwas kita tungod sa kamatayon ni Cristo, sa ato pa, napasaylo na ang atong mga sala” (Efeso 1:7). “Gipapas niya ang tanan tang mga utang lakip ang mga kasabotan bahin niini ug giwagtang niya ang tanan pinaagi sa paglansang niini didto sa krus” (Col. 2:14). Didto sa krus si Jesus miingon, “Natapos na” (Jn. 19:30) busa wala na kinahanglana ang pag-antos sa atong bahin kay si Cristo nag-antos na man alang kanato.","response":"Ang salang mortal dunay nalambigit nga duha ka matang sa silot ug kini mao kastigo eterno ug kastigo temporal. Ang usa ka tawo nga nagbuhat og salang mortal ug unya namatay nga wala maghinulsol silotan sa kastigo nga walay kataposan nga mao ang impyerno, “Apan ipahamtang sa Dios ang iyang kasuko ug kapungot sa mga tawo nga naghunahuna sa ilang kaugalingon ug nagsalikway sa kamatuoran aron pagbuhat sa daotan” (Rom. 2:8). Ang makapalikay nato niining maong kastigo mao ang atong paghimo ug maayo nga pagkompisal ngadto sa pari kay sila gitugyanan man ni Cristo sa gahom sa pagpasaylog mga sala, “Kon pasayloon ninyo ang mga sala sa mga tawo, gipasaylo kini; kon ang ilang mga sala dili ninyo pasayloon, dili usab kini pasayloon” (Jn. 20:23). Apan ang pagpasaylo sa sala dili sama sa pagwagtang sa kastigo temporal gumikan sa sala. Mahimo nga ang makasasala gipasaylo na sa Dios apan duna gihapon siyay mahiagoman nga kastigo temporal gumikan sa iyang mga sala. Si Miriam nga nakasala gipasaylo sa Dios apan ang Dios miingon kang Moises, “Pagawasa siya sa kampo sulod sa pito ka adlaw ug pagkatapos niana mahimo na nga pasudlon siya” (Num. 12:14). Ang Dios mipasaylo sa sala sa katawhan apan siya miingon, “Gipasaylo ko sila sumala sa imong gihangyo. Apan sa pagkatinuod, samtang buhi ako, ug ang tibuok kalibotan mapuno sa himaya sa Ginoo, walay mabuhi niining mga tawhana nga makasulod niadtong yutaa” (Num. 14:20-21). Bisan si Moises ug Aaron nahiagom usab sa kastigo temporal. Ang Dios miingon kanila, “Kay wala man ako tuohi ninyo, aron balaanon ako sa mga tawo sa Israel, dili kamo maoy mangulo sa mga tawo ngadto sa yuta nga akong ihatag kanila” (Num. 20:12). Si David bisan sa iyang paghinulsol apan nahiagom gihapon sa kastigo temporal. Si Natan miingon ngadto kaniya, “Gipasaylo sa Ginoo ang imong sala ug dili ka niya patyon. Apan kay pinaagi niining buhata imo mang gipasipad-an ang Ginoo, mamatay ang bata nga matawo kanimo” (2 Sam. 12:13-14). Kining maong kastigo kon dili nato kabayran niining kinabuhia adto kini antosan sa purgaturyo, “Niadtong adlawa ang buhat sa tagsatagsa sulayan pinaagi sa kalayo… kon ang iyang buhat dili hingpit siya mahiagom sa kastigo apan siya maluwas apan moagi una og kalayo” (1 Cor. 3:13-15). Si Jesus nagtudlo kanato sa paghimog pamayad samtang buhi pa kita, “pakighusay kaniya samtang may panahon pa ug wala pa kamo moabot didto; kay kon kamo moabot na sa hukmanan, itugyan ka niya sa huwes… ug timan-i: bilanggoon ka didto hangtod kabayran mo sa hingpit ang imong multa” (Mat. 5:26).\nAng pagtulon-an sa indulhensya gipasukad sa tulo ka hinungdanong panudlo: 1) gahom sa mga yawi. Ang makababag sa atong hingpit nga pag-ambit sa Iglesya dinhi sa yuta ug sa pagsulod ngadto sa langit mao ang sala ug ang silot temporal gumikan sa sala. Ang mga punoan sa Sta. Iglesya gihatagan sa Dios dili lamang sa gahom sa pagpasaylog mga sala kondili sa pagkuha usab sa kastigo temporal gumikan sa sala human kini mapasaylo sa kompisalan. Si Jesus miingon ngadto ni Pedro, “Ihatag ko kanimo ang mga yawi sa Gingharian sa langit; ang imong gapuson dinhi sa yuta gapuson usab didto sa langit; ug ang imong hubaran dinhi sa yuta, mahinubaran usab didto sa langit” (Mat. 16:19). Ngadto sa mga apostoles si Jesus miingon, “ang inyong idili dinhi sa yuta idili usab didto sa langit; ug ang inyong itugot dinhi sa yuta, itugot usab didto sa langit” (Mat. 18:18). Tungod niini nga gahom, ang Sto. Papa ug mga ka-Obispohan makahatag og indulhensya. 2) tigomanan sa grasya. Pinaagi sa kamatayon ni Cristo iyang nadaog alang kanato ang walay kinutuban nga bahandi sa grasya nga sobra kaayo nga ibayad sa atong mga utang “kay kon daghan ang nangamatay tungod sa pagpakasala sa usa ka tawo, labi pang dako ang grasya ug ang gasa sa Dios nga mabatonan sa daghang mga tawo pinaagi sa usa ka tawo nga mao si Jesu-Cristo” (Rom. 5:15). Nadugang niini mao ang mga merito sa mga santos tungod sa ilang giantos nga sobra kaayo nga ibayad sa ilang mga kasal-anan, “Kay pinaagi sa akong mga giantos nakatabang ako paghingpit sa wala pa matapos nga mga pag-antos ni Cristo alang sa iyang lawas nga mao ang iglesia” (Col. 1:24). Ang buluhaton sa pagpadangat niining maong grasya sa matag usa kanato gitugyan ni Jesus ngadto sa iyang Iglesya, “Isipa kami nga mga sulugoon ni Cristo nga gitugyanan sa mga tinagong kamatuoran sa Dios” (1 Cor. 4:1). 3) panaghiusa sa mga santos. Ang tanang sakop sa Iglesya dunay kalambigitan sa usag-usa tungod kay nahiusa man ang tanan diha sa usa ka lawas ug tungod niini ang mga lig-on nga bahin makatabang sa huyang nga bahin. “Daghan ug mga bahin ang atong lawas, ug ang matag bahin niini may kaugalingong bulohaton. Kita usab, bisan daghan, usa lamang ka lawas nga nahiusa kang Cristo, ug nalambigit kita sa usag-usa ingon nga nagkalainlaing bahin sa usa ka lawas” (Rom. 12:4-5). “Busa walay pagkabahinbahin sa lawas, kondili ang tanang bahin may samang pagtagad sa usag-usa. Kon ang usa ka bahin sa lawas mag-antos, ang ubang bahin mag-antos usab; kon daygon ang usa ka bahin, ang tanang bahin makaambit sa kalipay” (1 Cor. 12:25-26). Kini nagtudlo kanato nga diha sa mga sakop sa Sta. Iglesya dunay panag-ambitay sa mga maayong gasa sa grasya.\nAng Sta. Iglesya nag-ila sa duha ka matang sa indulhensya: indulhensya partial nga mopapas sa bahin lamang sa kastigo temporal ug ang indulhensya plenarya nga mopapas sa tibuok bayranan sa kastigon temporal. Ang mga kondisyon sa pagdawat sa indulhensya plenarya mao kining mosunod: 1) kinahanglan nga anaa sa kahimtang sa grasya. Si Jesus miingon, “Kon wala ako, wala kamoy mahimo” (Jn. 15:5). Makab-ot kini nato pinaagi sa pagkompisal ug sa pagkalawat. 2) kinahanglan nga ang modawat sa indulhensya andam nga mopailwaom sa autoridad (Sto. Papa o Obispo) nga naghatag, “Ug kon dili siya mamati sa iglesya, isipa siya nga usa ka langyaw o kobrador sa buhis” (Mat. 18:17). 3) kinahanglan ang tuyo sa pagdawat busa ato kining pangayoon, “pangayo kamo, ug kamo hatagan” (Mat. 7:7). 4) ang pagbuhat sa tulomanon nga gitudlo sa Sta. Iglesya sama pananglit sa pagbasa sa Kasulatan, paghimo sa mga acto sa debosyon sama sa pag-rosaryo ug pag-estasyon sa krus, sa pag-apil sa prosesyon, sa pagduaw sa mga “pilgrim center,” ug sa mga acto sa pagpasakit ug paghigugma sa isigkatawo. Ang Sta. Iglesya dunay gahom sa paghimo og mga lagda o tulomanon alang sa mga sakop, “Sa ilang pag-agi sa mga kalungsoran ilang gitugyan ngadto sa mga magtutuo ang mga lagda nga gikauyonan sa mga apostoles ug sa mga pangulo sa iglesia sa Jerusalem, ug gipahimangnoan sila sa pagtuman niini” (Buh. 16:4).\nAng pagtulon-an sa indulhensya dili masupak sa mga teksto nga gigamit sa atong mga kaatbang. Ang giingon sa Panultihon nga “ang gugma mopasaylo sa tanang kalapasan” nagpasabot kini nga ang dunay tinuod nga paghigugma sa iyang isigkatawo makamao gyod nga mopasaylo ug dili magdumot. Ang kompleto nga pasahe mao kini, “Makasamok ang pagdumot, apan ang gugma mopasaylo sa tanang kalapasan” (Prob. 10:12). Ang giingon nga “ang gugma nagtabon sa daghang mga sala” (1 Ped. 4:8) labot gihapon kini sa atong relasyon ngadto sa atong isigkatawo nga kinahanglan andam sa kita sa paghikalimot sa mga kasaypanan nga nabuhat nganhi kanato sa atong isigkatawo. Tinuod nga pinaagi sa dugo ni Cristo midangat kanato ang kapasayloan sa atong mga sala apan kinahanglan usab nga kita mohimo sa atong bahin sama sa pagtuo ug paghinulsol, ug sa pagdawat sa mga kastigo temporal gumikan sa atong mga sala ingon nga gasa gikan sa Dios aron kita mahingpit. “Kon kastigohon kita, makasubo kini kanato inay makalipay. Apan sa kaulahian kadtong nakadawat sa maong pagpanton makaani sa kinabuhing matarong ug ganting malinawon” (Heb. 12:11). Ang gipasabot ni San Pablo diha sa Col. 2:14 mao kadtong mga balaod sa Daang Tugon nga gipahunong na ug ang wala magtuman niadto dili na isipon nga sad-an kay si San Pablo mipadayon sa pag-ingon, “Busa ayaw ninyo itugot nga may magsaway kaninyo sa inyong kan-on o imnon, o bahin sa mga adlaw nga balaan, o sa pangilin sa bag-ong bulan… Kining tanan mga landong lamang sa mga butang nga umaabot, apan ang katumanan mao si Cristo” (Col. 2:16-17). Ang pag-ingon ni Jesus nga “natapos na” mahitungod kini sa iyang misyon sa pagpanubos kanato apan kita usab gitawag aron sa pag-ambit sa mga pag-antos ni Cristo, “Kay gihatagan kamo sa pribilihiyo, dili lamang sa pagtuo kang Cristo, kondili sa pagpasakit usab tungod kaniya” (Fil 1:29)."}]'::jsonb, '["Prob. 10:12","1 Ped. 4:8","Efeso 1:7","Col. 2:14","Jn. 19:30","Rom. 2:8","Jn. 20:23","Num. 12:14","Num. 14:20-21","Num. 20:12","2 Sam. 12:13-14","1 Cor. 3:13-15","Mat. 5:26","Mat. 16:19","Mat. 18:18","Rom. 5:15","Col. 1:24","1 Cor. 4:1","Rom. 12:4-5","1 Cor. 12:25-26","Jn. 15:5","Mat. 18:17","Mat. 7:7","Buh. 16:4","Heb. 12:11","Col. 2:16-17","Fil 1:29"]'::jsonb, '["indulgences"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.045Z')
